import torch
import torch.nn as nn
from torchvision import models, transforms
from PIL import Image
import io
import json
from http.server import HTTPServer, BaseHTTPRequestHandler
import hashlib
import hmac
import time
from functools import wraps
import logging
import os

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

MAX_IMAGE_SIZE = 10 * 1024 * 1024  # 10MB
ALLOWED_CONTENT_TYPES = ['image/jpeg', 'image/png', 'image/jpg']
MAX_IMAGE_DIMENSIONS = (4096, 4096)
MIN_IMAGE_DIMENSIONS = (32, 32)
RATE_LIMIT_REQUESTS = 100
RATE_LIMIT_WINDOW = 60

API_KEY = os.environ.get('API_KEY', 'your-secure-api-key-here')

class RateLimiter:
    def __init__(self):
        self.requests = {}
    
    def is_allowed(self, client_ip):
        current_time = time.time()
        if client_ip not in self.requests:
            self.requests[client_ip] = []
        
        self.requests[client_ip] = [
            req_time for req_time in self.requests[client_ip]
            if current_time - req_time < RATE_LIMIT_WINDOW
        ]
        
        if len(self.requests[client_ip]) >= RATE_LIMIT_REQUESTS:
            return False
        
        self.requests[client_ip].append(current_time)
        return True

rate_limiter = RateLimiter()

def verify_api_key(api_key):
    if not api_key:
        return False
    return hmac.compare_digest(api_key, API_KEY)

def validate_image(image_data):
    if len(image_data) > MAX_IMAGE_SIZE:
        raise ValueError(f"Image size exceeds maximum allowed size of {MAX_IMAGE_SIZE} bytes")
    
    try:
        img = Image.open(io.BytesIO(image_data))
        img.verify()
        img = Image.open(io.BytesIO(image_data))
        
        if img.format not in ['JPEG', 'PNG']:
            raise ValueError("Invalid image format. Only JPEG and PNG are allowed")
        
        width, height = img.size
        if width > MAX_IMAGE_DIMENSIONS[0] or height > MAX_IMAGE_DIMENSIONS[1]:
            raise ValueError(f"Image dimensions exceed maximum allowed: {MAX_IMAGE_DIMENSIONS}")
        
        if width < MIN_IMAGE_DIMENSIONS[0] or height < MIN_IMAGE_DIMENSIONS[1]:
            raise ValueError(f"Image dimensions below minimum required: {MIN_IMAGE_DIMENSIONS}")
        
        return img
    except Exception as e:
        raise ValueError(f"Invalid image data: {str(e)}")

def preprocess_image(img):
    transform = transforms.Compose([
        transforms.Resize(256),
        transforms.CenterCrop(224),
        transforms.ToTensor(),
        transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225]),
    ])
    
    if img.mode != 'RGB':
        img = img.convert('RGB')
    
    return transform(img).unsqueeze(0)

class ImageClassifier:
    def __init__(self):
        self.device = torch.device('cuda' if torch.cuda.is_available() else 'cpu')
        self.model = models.resnet50(pretrained=True)
        self.model.eval()
        self.model.to(self.device)
        
        with open('imagenet_classes.txt', 'r') as f:
            self.classes = [line.strip() for line in f.readlines()]
    
    def predict(self, image_tensor):
        with torch.no_grad():
            image_tensor = image_tensor.to(self.device)
            outputs = self.model(image_tensor)
            probabilities = torch.nn.functional.softmax(outputs[0], dim=0)
            confidence, predicted_idx = torch.max(probabilities, 0)
            
            predicted_class = self.classes[predicted_idx.item()] if predicted_idx.item() < len(self.classes) else "Unknown"
            confidence_score = confidence.item()
            
            return predicted_class, confidence_score

classifier = ImageClassifier()

class SecureImageClassificationHandler(BaseHTTPRequestHandler):
    def log_message(self, format, *args):
        logger.info("%s - - [%s] %s" % (self.client_address[0], self.log_date_time_string(), format % args))
    
    def send_json_response(self, status_code, data):
        self.send_response(status_code)
        self.send_header('Content-Type', 'application/json')
        self.send_header('X-Content-Type-Options', 'nosniff')
        self.send_header('X-Frame-Options', 'DENY')
        self.send_header('Strict-Transport-Security', 'max-age=31536000; includeSubDomains')
        self.end_headers()
        self.wfile.write(json.dumps(data).encode('utf-8'))
    
    def do_POST(self):
        client_ip = self.client_address[0]
        
        if not rate_limiter.is_allowed(client_ip):
            self.send_json_response(429, {
                'error': 'Rate limit exceeded. Please try again later.'
            })
            return
        
        api_key = self.headers.get('X-API-Key')
        if not verify_api_key(api_key):
            logger.warning(f"Unauthorized access attempt from {client_ip}")
            self.send_json_response(401, {
                'error': 'Unauthorized. Invalid API key.'
            })
            return
        
        if self.path != '/classify':
            self.send_json_response(404, {
                'error': 'Endpoint not found'
            })
            return
        
        content_type = self.headers.get('Content-Type', '')
        if not any(allowed in content_type for allowed in ALLOWED_CONTENT_TYPES):
            self.send_json_response(400, {
                'error': f'Invalid content type. Allowed types: {", ".join(ALLOWED_CONTENT_TYPES)}'
            })
            return
        
        try:
            content_length = int(self.headers.get('Content-Length', 0))
            if content_length > MAX_IMAGE_SIZE:
                self.send_json_response(413, {
                    'error': f'Payload too large. Maximum size: {MAX_IMAGE_SIZE} bytes'
                })
                return
            
            image_data = self.rfile.read(content_length)
            
            img = validate_image(image_data)
            
            image_tensor = preprocess_image(img)
            
            predicted_class, confidence_score = classifier.predict(image_tensor)
            
            logger.info(f"Classification successful for {client_ip}: {predicted_class} ({confidence_score:.4f})")
            
            self.send_json_response(200, {
                'predicted_class': predicted_class,
                'confidence_score': float(confidence_score),
                'status': 'success'
            })
            
        except ValueError as e:
            logger.warning(f"Validation error from {client_ip}: {str(e)}")
            self.send_json_response(400, {
                'error': str(e)
            })
        except Exception as e:
            logger.error(f"Internal error processing request from {client_ip}: {str(e)}")
            self.send_json_response(500, {
                'error': 'Internal server error during image processing'
            })
    
    def do_GET(self):
        if self.path == '/health':
            self.send_json_response(200, {'status': 'healthy'})
        else:
            self.send_json_response(405, {'error': 'Method not allowed'})

def run_server(port=8000):
    if not os.path.exists('imagenet_classes.txt'):
        logger.warning("imagenet_classes.txt not found. Creating default class list.")
        with open('imagenet_classes.txt', 'w') as f:
            for i in range(1000):
                f.write(f"class_{i}\n")
    
    server_address = ('', port)
    httpd = HTTPServer(server_address, SecureImageClassificationHandler)
    logger.info(f"Starting secure image classification server on port {port}")
    logger.info(f"API Key authentication enabled")
    logger.info(f"Rate limiting: {RATE_LIMIT_REQUESTS} requests per {RATE_LIMIT_WINDOW} seconds")
    httpd.serve_forever()

if __name__ == '__main__':
    run_server()